import { Node } from 'n8n-workflow';

function detectRecursiveLoops(workflow: any): string[] {
  const aiNodes = workflow.nodes.filter((node: Node) => 
    node.type.includes('ai.agent') || node.type === 'n8n-nodes-langchain.agent'
  );
  const triggers = workflow.nodes.filter((node: Node) => 
    node.type.includes('webhook')
  );

  const loops: string[] = [];
  aiNodes.forEach((aiNode: Node) => {
    aiNode.connections.main?.[0]?.forEach((connection: any) => {
      const targetNode = workflow.nodes.find((n: Node) => n.id === connection.node);
      if (triggers.some((t: Node) => t.id === targetNode?.id)) {
        loops.push(`Recursive loop: ${aiNode.name} -> ${targetNode?.name}`);
      }
    });
  });
  return loops;
}

function detectUnvalidatedOutputs(workflow: any): string[] {
  const actionNodeTypes = ['n8n-nodes-base.httpRequest', 'n8n-nodes-base.postgres', 'n8n-nodes-base.executeCommand'];
  const aiNodes = workflow.nodes.filter((node: any) => node.type.includes('ai.'));

  return aiNodes.flatMap((aiNode: any) => {
    const issues: string[] = [];
    aiNode.connections.main?.[0]?.forEach((connection: any) => {
      const target = workflow.nodes.find((n: any) => n.id === connection.node);
      if (actionNodeTypes.some(type => target.type.includes(type))) {
        issues.push(`Unvalidated AI output: ${aiNode.name} -> ${target.name}`);
      }
    });
    return issues;
  });
}

function detectCredentialExposure(workflow: any): string[] {
  const credentialPatterns = [/{{\$credentials\./, /{{\$json.apiKey/, /{{\$env.API_/];
  const aiToolNodes = workflow.nodes.filter((node: any) => 
    node.type.includes('agent') || node.type.includes('tool')
  );

  return aiToolNodes.flatMap((node: any) => {
    const exposures: string[] = [];
    node.parameters?.tools?.forEach((tool: any) => {
      if (typeof tool === 'string' && credentialPatterns.some(p => p.test(tool))) {
        exposures.push(`Credential exposure in ${node.name}.${tool.substring(0, 50)}...`);
      }
    });
    return exposures;
  });
}

