// Secure credentials before passing to AI tools
const items = $input.all();

for (const item of items) {
  const params = { ...item.json };

  // Mask credentials in tool parameters
  Object.keys(params).forEach(key => {
    if (typeof params[key] === 'string') {
      // Remove credential patterns
      params[key] = params[key].replace(/\{\{\$credentials\..*?\}\}/g, '[CREDENTIAL]');
      params[key] = params[key].replace(/\{\{\$env\..*?\}\}/g, '[ENV_VAR]');
    }
  });

  item.json.safeParams = params;
}

return items;

// Validate memory context before AI Agent
const items = $input.all();
const now = new Date().getTime();

const MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours

for (const item of items) {
  if (item.json.memory?.sessions) {
    item.json.validatedMemory = item.json.memory.sessions
      .filter((session: any) => {
        const sessionTime = new Date(session.timestamp).getTime();
        const isRecent = (now - sessionTime) < MAX_AGE_MS;
        const isSameUser = session.userId === item.json.userId;
        return isRecent && isSameUser;
      })
      .slice(-5); // Keep last 5 valid sessions
  }

  if (!item.json.validatedMemory?.length) {
    item.json.validatedMemory = [{ role: 'system', content: 'No recent conversation context available.' }];
  }
}

return items;

