import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  webhookSecret: process.env.VEX_WEBHOOK_SECRET!,
  detectors: ['n8n-ai-recursive-loop', 'n8n-ai-unvalidated-output', 'n8n-ai-credential-exposure', 'n8n-ai-stale-memory']
});

// n8n webhook node code for Vex integration
export default defineWebhookHandler(async (req, res) => {
  const executionData = await req.json();

  // Auto-detect all 4 error patterns
  const issues = await vex.detect({
    framework: 'n8n',
    workflowId: $execution.id,
    aiNodeOutput: executionData.json,
    fullPayload: executionData
  });

  if (issues.length > 0) {
    // Block execution and return remediation
    const remediation = await vex.remediate(issues);
    return res.status(400).json({
      error: 'AI Agent errors detected',
      issues,
      fix: remediation.n8nCodeNode
    });
  }

  // Forward to next node if clean
  return res.status(200).json(executionData);
});
